export const mapStats = (vehicles) => {
  const counts = { idle: 0, queuing: 0, onTask: 0, abnormal: 0 }
  vehicles.forEach((v) => { if (counts[v.status] !== undefined) counts[v.status]++ })
  return [
    { key: 'idle', label: '空闲', value: counts.idle, color: '#16a34a' },
    { key: 'queuing', label: '排队', value: counts.queuing, color: '#d97706' },
    { key: 'onTask', label: '任务中', value: counts.onTask, color: '#2563eb' },
    { key: 'abnormal', label: '异常', value: counts.abnormal, color: '#dc2626' },
  ]
}
